#include <stdio.h>
#include <string.h>
#define MOD 1000000007LL

long long countSubsequences(const char *s1, const char *s2) {
    int m = strlen(s1), n = strlen(s2);
    long long dp[m+1][n+1];
    for (int i = 0; i <= m; ++i) dp[i][0] = 1;
    for (int j = 1; j <= n; ++j) dp[0][j] = 0;
    for (int i = 1; i <= m; ++i) {
        for (int j = 1; j <= n; ++j) {
            if (s1[i-1] == s2[j-1])
                dp[i][j] = (dp[i-1][j-1] + dp[i-1][j]) % MOD;
            else
                dp[i][j] = dp[i-1][j];
        }
    }
    return dp[m][n];
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char s1[101], s2[101];
        scanf("%100s %100s", s1, s2);
        printf("%lld\n", countSubsequences(s1, s2));
    }
    return 0;
}

