import sys
MOD = 10**9 + 7

def count_subseq(s1, s2):
    m, n = len(s1), len(s2)
    dp = [[0]*(n+1) for _ in range(m+1)]
    for i in range(m+1):
        dp[i][0] = 1
    for i in range(1, m+1):
        for j in range(1, n+1):
            if s1[i-1] == s2[j-1]:
                dp[i][j] = (dp[i-1][j-1] + dp[i-1][j]) % MOD
            else:
                dp[i][j] = dp[i-1][j]
    return dp[m][n]

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out = []
    for _ in range(t):
        s1 = data[idx]
        s2 = data[idx+1]
        idx += 2
        out.append(str(count_subseq(s1, s2)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

